import { useState, useMemo } from 'react';
import { useApp } from '../context/AppContext';
import { checkAvailabilityAPI, confirmBookingAPI } from '../services/api';
import Button from '../components/Button';
import Input from '../components/Input';
import '../css/RoomDetailPage.css';

export default function RoomDetailPage() {
  const { state, dispatch } = useApp();
  const room = state.selectedRoom;

  // Aaj ki date nikalne ke liye
  const today = new Date().toISOString().split('T')[0];

  // States
  const [dates, setDates] = useState({ checkIn: today, checkOut: '' });
  const [errors, setErrors] = useState({});
  const [checking, setChecking] = useState(false);
  const [availability, setAvailability] = useState(null);
  const [confirming, setConfirming] = useState(false);

  // Nights calculation logic
  const nights = useMemo(() => {
    if (!dates.checkIn || !dates.checkOut) return 0;
    const diff = (new Date(dates.checkOut) - new Date(dates.checkIn)) / 86400000;
    return diff > 0 ? diff : 0;
  }, [dates]);

  const total = nights * (room?.price || 0);

  // Form Validation
  const validate = () => {
    const e = {};
    if (!dates.checkIn) e.checkIn = 'Select check-in date';
    if (!dates.checkOut) e.checkOut = 'Select check-out date';
    if (dates.checkIn && dates.checkOut && dates.checkOut <= dates.checkIn)
      e.checkOut = 'Check-out must be after check-in';
    if (dates.checkIn < today) e.checkIn = 'Cannot select a past date';
    return e;
  };

  const handleDateChange = (e) => {
    setDates((d) => ({ ...d, [e.target.name]: e.target.value }));
    setAvailability(null); // Date change hote hi purani availability clear karo
    setErrors((err) => ({ ...err, [e.target.name]: '' }));
  };

  // Check Availability Logic
  const handleCheckAvailability = async () => {
    const e = validate();
    if (Object.keys(e).length) {
      setErrors(e);
      return;
    }
    setChecking(true);
    setAvailability(null);
    try {
      const result = await checkAvailabilityAPI(
        room.id,
        dates.checkIn,
        dates.checkOut,
        state.bookings
      );
      setAvailability(result.available ? 'available' : 'unavailable');
    } catch {
      dispatch({
        type: 'SET_NOTIFICATION',
        payload: { type: 'error', msg: 'Failed to check availability.' },
      });
    } finally {
      setChecking(false);
    }
  };

  // Confirm Booking Logic
  const handleConfirmBooking = async () => {
    setConfirming(true);
    try {
      await confirmBookingAPI({ roomId: room.id, ...dates });

      // Global state mein booking add karna
      dispatch({
        type: 'ADD_BOOKING',
        payload: {
          id: Date.now(),
          roomId: room.id,
          roomName: room.name,
          roomImage: room.image,
          roomType: room.type,
          checkIn: dates.checkIn,
          checkOut: dates.checkOut,
          nights,
          total,
          bookedAt: new Date().toLocaleDateString('en-IN'),
        },
      });

      // Success ke baad "My Bookings" page par bhejna
      dispatch({ type: 'SET_PAGE', payload: 'bookings' });

    } catch (err) {
      dispatch({
        type: 'SET_NOTIFICATION',
        payload: { type: 'error', msg: 'Booking failed. Please try again.' },
      });
    } finally {
      setConfirming(false);
    }
  };

  // Agar room select nahi hai toh error message dikhao
  if (!room) {
    return (
      <div className="page-wrap">
        <center>
          <p>No room selected.</p>
          <Button onClick={() => dispatch({ type: 'SET_PAGE', payload: 'dashboard' })}>
            Back to Dashboard
          </Button>
        </center>
      </div>
    );
  }

  return (
    <div className="page-wrap">
      <button
        className="btn btn-ghost"
        style={{ marginBottom: 24 }}
        onClick={() => dispatch({ type: 'SET_PAGE', payload: 'dashboard' })}
      >
        ← Back to Rooms
      </button>

      <div className="layout">
        {/* Left Section: Room Details */}
        <div className="room-info-section">
          <div className="hero">
            {/* FIXED: Image error handling taaki path wala text na dikhe */}
            {typeof room.image === 'string' && room.image.length > 5 ? (
              <img 
                src={room.image} 
                alt={room.name} 
                className="hero-img" 
                onError={(e) => {
                    e.target.style.display = 'none'; // Image hide karo agar path galat ho
                    e.target.nextSibling.style.display = 'flex'; // Emoji dikhao
                }}
              />
            ) : null}
            <div style={{ display: 'none', fontSize: 80, height: '100%', alignItems: 'center', justifyContent: 'center' }}>🏨</div>
          </div>

          <div className="room-type">{room.type}</div>
          <h1 className="room-name">{room.name}</h1>

          <div className="info-grid">
            <div className="info-item">
              <div className="info-label">Price per night</div>
              <div className="info-value">₹{room.price?.toLocaleString()}</div>
            </div>
            <div className="info-item">
              <div className="info-label">Capacity</div>
              <div className="info-value">
                {room.capacity} {room.capacity > 1 ? 'guests' : 'guest'}
              </div>
            </div>
          </div>

          <div className="amen-label">Amenities</div>
          <div className="amenities-list">
            {room.amenities?.map((a) => (
              <span key={a} className="amen-tag">
                {a}
              </span>
            ))}
          </div>
        </div>

        {/* Right Section: Booking Panel */}
        <div className="booking-panel">
          <h3 className="panel-title">Reserve This Room</h3>

          <div className="price-box">
            <div className="big-price">₹{room.price?.toLocaleString()}</div>
            <div style={{ fontSize: 12, color: 'var(--muted)' }}>per night</div>
          </div>

          <Input
            label="Check-in Date"
            type="date"
            name="checkIn"
            value={dates.checkIn}
            min={today}
            onChange={handleDateChange}
            error={errors.checkIn}
          />
          <Input
            label="Check-out Date"
            type="date"
            name="checkOut"
            value={dates.checkOut}
            min={dates.checkIn || today}
            onChange={handleDateChange}
            error={errors.checkOut}
          />

          {nights > 0 && (
            <div className="total-row">
              <span style={{ fontSize: 13, color: 'var(--muted)' }}>
                {nights} night{nights > 1 ? 's' : ''} × ₹
                {room.price?.toLocaleString()}
              </span>
              <span className="total-price">₹{total.toLocaleString()}</span>
            </div>
          )}

          {availability && (
            <div
              className={`avail-badge ${availability === 'available' ? 'avail-yes' : 'avail-no'}`}
            >
              {availability === 'available'
                ? '✓ Room is available!'
                : '✗ Not available for selected dates'}
            </div>
          )}

          {/* Button Switching Logic */}
          {availability !== 'available' ? (
            <Button
              variant="outline"
              fullWidth
              loading={checking}
              onClick={handleCheckAvailability}
            >
              Check Availability
            </Button>
          ) : (
            <Button
              variant="gold"
              fullWidth
              loading={confirming}
              onClick={handleConfirmBooking}
              style={{ marginTop: 8 }}
            >
              Confirm Booking →
            </Button>
          )}
        </div>
      </div>
    </div>
  );
}
